{:version=>3, :sections=>[{:offset=>{:line=>0, :column=>0}, :map=>{:version=>3, :sourceRoot=>"", :sources=>["bcdice/user_defined_dice_table.rb"], :sourcesContent=>["# frozen_string_literal: true\n\nmodule BCDice\n  # テキストで定義したダイス表を実行するクラス\n  #\n  # @example\n  #   text = <<~TEXT\n  #     飲み物表\n  #     1D6\n  #     1:水\n  #     2:緑茶\n  #     3:麦茶\n  #     4:コーラ\n  #     5:オレンジジュース\n  #     6:選ばれし者の知的飲料\n  #   TEXT\n  #   table = BCDice::UserDefinedDiceTable.new(text)\n  #   table.valid?() #=> true\n  #   table.roll().text #=> \"飲み物表(6) ＞ 選ばれし者の知的飲料\"\n  #   BCDice::UserDefinedDiceTable.eval(text) #=> #<BCDice::Result>\n  #\n  class UserDefinedDiceTable\n    class << self\n      # @param text [String]\n      # @return [Result nil]\n      def roll(text)\n        new(text).roll()\n      end\n    end\n\n    # @param text [String] ダイス表のテキストデータ\n    def initialize(text)\n      @text = text\n      @rows = nil\n    end\n\n    # ダイス表をロールする\n    # @param randomizer [Randomizer]\n    # @return [Result, nil]\n    def roll(randomizer: Randomizer.new)\n      parse()\n\n      index = roll_index(randomizer)\n      unless valid? && index\n        return nil\n      end\n\n      key = \"\#{index}:\"\n      row = @rows.find { |l| l.start_with?(key) }\n      unless row\n        return nil\n      end\n\n      chosen = row.delete_prefix(key).gsub('\\n', \"\\n\").strip\n      Result.new.tap do |r|\n        r.text = \"\#{@name}(\#{index}) ＞ \#{chosen}\"\n        r.rands = randomizer.rand_results\n        r.detailed_rands = randomizer.detailed_rand_results\n      end\n    end\n\n    # 有効なダイス表かをチェックする。テキスト形式のミスだけではなく、抜けている出目や範囲外の出目がないか確認する。\n    # @return [Boolean]\n    def valid?\n      parse()\n\n      has_index = @rows.all? { |row| /^\\d+:/.match?(row) }\n      unless has_index\n        return false\n      end\n\n      index_list = @rows.map(&:to_i).uniq.sort\n\n      case @type\n      when /^\\d+D\\d+$/\n        valid_d?(index_list)\n      when \"D66\", \"D66N\"\n        valid_d66?(index_list)\n      when \"D66A\", \"D66S\"\n        valid_d66_asc_sort?(index_list)\n      when \"D66D\"\n        valid_d66_desc_sort?(index_list)\n      else\n        false\n      end\n    end\n\n    private\n\n    # @return [Integer, nil]\n    def roll_index(randomizer)\n      if (m = /^(\\d+)D(\\d+)$/.match(@type))\n        times = m[1].to_i\n        sides = m[2].to_i\n        return randomizer.roll_sum(times, sides)\n      end\n\n      case @type\n      when \"D66\", \"D66N\"\n        randomizer.roll_d66(D66SortType::NO_SORT)\n      when \"D66A\", \"D66S\"\n        randomizer.roll_d66(D66SortType::ASC)\n      when \"D66D\"\n        randomizer.roll_d66(D66SortType::DESC)\n      end\n    end\n\n    def parse\n      return if @rows\n\n      lines = @text.split(/\\r?\\n/).map(&:rstrip).reject(&:empty?)\n      @name = lines.shift\n      @type = lines.shift.upcase\n      @rows = lines\n    end\n\n    def valid_d?(index_list)\n      m = /^(\\d+)D(\\d+)$/.match(@type)\n      times = m[1].to_i\n      sides = m[2].to_i\n\n      expected_size = times * sides - times + 1\n      if index_list.size != expected_size\n        return false\n      end\n\n      return index_list.first == times && index_list.last == times * sides\n    end\n\n    def valid_d66?(index_list)\n      if index_list.size != 36\n        return false\n      end\n\n      expected_index = (1..6).map do |tens|\n        (1..6).map { |ones| tens * 10 + ones }\n      end.flatten\n\n      return index_list == expected_index\n    end\n\n    def valid_d66_asc_sort?(index_list)\n      if index_list.size != 21\n        return false\n      end\n\n      expected_index = (1..6).map do |tens|\n        (tens..6).map { |ones| tens * 10 + ones }\n      end.flatten\n\n      return index_list == expected_index\n    end\n\n    def valid_d66_desc_sort?(index_list)\n      if index_list.size != 21\n        return false\n      end\n\n      expected_index = (1..6).map do |ones|\n        (ones..6).map { |tens| tens * 10 + ones }\n      end.flatten.sort\n\n      return index_list == expected_index\n    end\n  end\nend\n"], :names=>["<main>", "<module:BCDice>", "<class:UserDefinedDiceTable>", "roll", "text", "self", "new", "initialize", "@text", "@rows", "$kwargs", "Randomizer", "parse", "index", "roll_index", "randomizer", "valid?", "key", "row", "find", "block in roll", "l", "block (2 levels) in roll", "start_with?", "chosen", "delete_prefix", "gsub", "strip", "tap", "Result", "r", "text=", "@name", "rands=", "rand_results", "detailed_rands=", "detailed_rand_results", "has_index", "all?", "block in valid?", "block (2 levels) in valid?", "match?", "index_list", "map", "to_proc", "uniq", "sort", "$ret_or_1", "@type", "valid_d?", "valid_d66?", "valid_d66_asc_sort?", "valid_d66_desc_sort?", "private", "m", "match", "times", "[]", "1", "to_i", "sides", "2", "roll_sum", "roll_d66", "D66SortType::NO_SORT", "D66SortType", "D66SortType::ASC", "D66SortType::DESC", "lines", "reject", "split", "shift", "upcase", "expected_size", "+", "-", "*", "size", "first", "==", "last", "36", "expected_index", "6", "block in valid_d66?", "tens", "block (2 levels) in valid_d66?", "ones", "block (3 levels) in valid_d66?", "10", "flatten", "21", "block in valid_d66_asc_sort?", "block (2 levels) in valid_d66_asc_sort?", "block (3 levels) in valid_d66_asc_sort?", "block in valid_d66_desc_sort?", "block (2 levels) in valid_d66_desc_sort?", "block (3 levels) in valid_d66_desc_sort?"], :mappings=>"AAAAA,2BAAAA;EAAAA;;EAEAA,OAAAC;EAAAA;;IAAAA;;IAmBEA,OAAAC;IAAAA;;MAAAA;;AAAAA;;MACE;;QAGE,OAAAC,oBAAAA,gBAASC,IAATD;AAAAA,UAAAA;;UACEA,OAAAE,IAAAC,KAAAA,CAAIF,IAAJE,CAASH,MAAAA,CAAAA;QADXA,CAAAA;MAHF,4BAASE,IAAT;;AASAE,MAAAA,0BAAAA,sBAAeH,IAAfG;AAAAA,QAAAA;;;QACEC,YAAQJ;QACRG,OAAAE,CAAAA,YAAQ,GAARA;MAFFF,CAAAA;;AAQAJ,MAAAA,oBAAAA,gBAvCJO,OAuCIP;AAAAA,QAAAA;;;QAvCJ;;QAuCa,0CAAA,qCAAYQ,gBAAUL,KAAAA,CAAAA;QAC7BD,IAAAO,OAAAA,CAAAA;QAEAC,QAAQR,IAAAS,YAAAA,CAAWC,UAAXD;QACR,KAAO,CAAA,QAAAT,IAAAW,WAAAA,CAAAA,CAAA,CAAA,IAAA,CAAA,QAAUH,KAAV,CAAA,CAA